import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import org.junit.jupiter.api.Test;

class TypeAdaptersTest {

  @Test
  void newFactory_createsFactoryThatReturnsAdapterForUnboxedAndBoxedTypes() {
    // Arrange
    TypeAdapter<Number> mockAdapter = mock(TypeAdapter.class);
    Class<Integer> unboxed = int.class;
    Class<Integer> boxed = Integer.class;

    TypeAdapterFactory factory = TypeAdapters.newFactory(unboxed, boxed, mockAdapter);

    Gson mockGson = mock(Gson.class);

    TypeToken<Integer> typeTokenUnboxed = TypeToken.get(unboxed);
    TypeToken<Integer> typeTokenBoxed = TypeToken.get(boxed);
    TypeToken<Long> typeTokenOther = TypeToken.get(Long.class);

    // Act & Assert
    // For unboxed type
    TypeAdapter<Integer> adapterUnboxed = factory.create(mockGson, typeTokenUnboxed);
    assertNotNull(adapterUnboxed);
    assertSame(mockAdapter, adapterUnboxed);

    // For boxed type
    TypeAdapter<Integer> adapterBoxed = factory.create(mockGson, typeTokenBoxed);
    assertNotNull(adapterBoxed);
    assertSame(mockAdapter, adapterBoxed);

    // For other type
    TypeAdapter<Long> adapterOther = factory.create(mockGson, typeTokenOther);
    assertNull(adapterOther);

    // Test toString contains expected strings
    String toString = factory.toString();
    assertTrue(toString.contains(boxed.getName()));
    assertTrue(toString.contains(unboxed.getName()));
    assertTrue(toString.contains(mockAdapter.toString()));
  }
}
